const d = $json;

// parcelas: acepta array o string coma-separado
let parcelas = [];
if (Array.isArray(d.parcelas)) parcelas = d.parcelas;
else if (typeof d.parcelas === 'string' && d.parcelas.trim()) parcelas = d.parcelas.split(/[,\s]+/).filter(Boolean);
parcelas = parcelas.map(p => String(p).toUpperCase().trim()).filter(Boolean);

if (parcelas.length === 0) throw new Error('parcelas requerido (al menos una)');

const nombre = (d.nombre || '').toString().trim().slice(0, 120);
const resumen = (d.resumen || '').toString().trim().slice(0, 1500);

if (!nombre) throw new Error('nombre requerido');

// Canal se infiere de qué campos vienen con valor válido.
const emailRaw = (d.email || '').toString().trim();
const waRaw = (d.whatsapp || '').toString().trim();

const emailValidRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const email = emailRaw && emailValidRe.test(emailRaw) ? emailRaw : '';

let waClean = waRaw.replace(/[^0-9]/g, '');
if (waClean.startsWith('9') && waClean.length === 9) waClean = '56' + waClean;
const whatsapp = waClean.length >= 10 ? waClean : '';

if (!email && !whatsapp) throw new Error('email y/o whatsapp requerido');

return [{ json: {
  nombre,
  email,
  whatsapp,
  parcelas,
  resumen,
  send_email: !!email,
  send_whatsapp: !!whatsapp,
} }];

// Parsea CSV del Sheet, filtra parcelas pedidas y arma pdfData + flags de envío.
const input = $('Validate Input').first().json;
const sheetItem = $json;

const nombreFull = input.nombre;
const primerNombre = nombreFull.split(' ')[0] || 'Cliente';

const csvText = ((sheetItem && (sheetItem.data || sheetItem.body)) || '').toString();
function parseCsv(text) {
  const rows = [];
  let row = []; let field = ''; let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (c === '"') {
      if (inQuotes && text[i + 1] === '"') { field += '"'; i++; }
      else inQuotes = !inQuotes;
    } else if (c === ',' && !inQuotes) { row.push(field); field = ''; }
    else if ((c === '\n' || c === '\r') && !inQuotes) {
      if (c === '\r' && text[i + 1] === '\n') i++;
      row.push(field); rows.push(row); row = []; field = '';
    } else field += c;
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}
const pm = (s) => { if (!s) return null; const t = s.toString(); if (t.includes('#')) return null; const n = t.replace(/[^0-9]/g, ''); return n ? parseInt(n, 10) : null; };
const ps = (s) => { if (!s) return null; const n = s.toString().replace(/[^0-9]/g, ''); return n ? parseInt(n, 10) : null; };
const normEstado = (r) => { const e = (r || '').toString().trim().toLowerCase(); if (e.startsWith('disponi')) return 'disponible'; if (e.startsWith('reserv')) return 'reservado'; if (e.startsWith('vendi')) return 'vendido'; return e; };

const rows = parseCsv(csvText);
const byNumero = new Map();
for (const r of rows) {
  if (!r || r.length < 3) continue;
  const lote = (r[1] || '').toString().trim();
  if (!/^(\d{1,3}|B\d{1,2})$/i.test(lote)) continue;
  byNumero.set(lote.toUpperCase(), {
    numero: lote.toUpperCase(),
    destacada: ((r[0] || '').toString().trim() === '⭐'),
    estado: normEstado(r[2]),
    tamano_m2: ps(r[3]),
    precio_contado: pm(r[6]),
    descuento_pct: ps(r[7]),
    precio_credito: pm(r[9]),
    pie_minimo_50pct: pm(r[10]),
    cuota_mensual_clp: pm(r[11]),
  });
}

const parcelas = input.parcelas
  .map(n => byNumero.get(n.toUpperCase()))
  .filter(Boolean);

const pdfData = {
  primerNombre,
  resumen_conversacion: (input.resumen || '').trim(),
  parcelas: parcelas.map(p => ({
    numero: p.numero,
    destacada: !!p.destacada,
    estado: p.estado,
    tamano_m2: p.tamano_m2,
    precio_contado: p.precio_contado,
    descuento_pct: p.descuento_pct,
    precio_credito: p.precio_credito,
    pie_minimo_50pct: p.pie_minimo_50pct,
    cuota_mensual_clp: p.cuota_mensual_clp,
  })),
  base_url: 'https://mirador-villarrica-chatbot.vercel.app',
};

return [{ json: {
  nombre: nombreFull,
  primerNombre,
  email: input.email,
  phone_clean: input.whatsapp,
  can_email: input.send_email,
  can_whatsapp: input.send_whatsapp,
  pdfData,
  parcelas_ok: parcelas.length,
} }];

const built = $('Build PDF Data').first().json;
const primerNombre = built.primerNombre || 'hola';

const sent = [];
const failed = [];
let waError = null;
let emailError = null;

// --- EMAIL ---
if (built.can_email) {
  let gmailResp = null;
  try { gmailResp = $('Gmail Send Resumen').first(); } catch (_) { gmailResp = null; }
  const gmailOk = gmailResp && !gmailResp.error && gmailResp.json && (gmailResp.json.id || gmailResp.json.threadId || gmailResp.json.labelIds);
  if (gmailOk) sent.push('email');
  else { failed.push('email'); emailError = (gmailResp && gmailResp.error && gmailResp.error.message) || 'gmail_error'; }
}

// --- WHATSAPP ---
if (built.can_whatsapp) {
  let waResp = null;
  try { waResp = $('Evolution Send WA').first().json; } catch (_) { waResp = null; }
  const statusCode = waResp && typeof waResp.status === 'number' ? waResp.status : null;
  const respBody = waResp ? (waResp.response || waResp) : null;
  const message = respBody && respBody.message;
  const notRegistered = Array.isArray(message) && message.some(m => m && m.exists === false);
  if (notRegistered) { failed.push('whatsapp'); waError = 'numero_no_registrado'; }
  else if (statusCode && statusCode >= 400) { failed.push('whatsapp'); waError = 'api_error'; }
  else if (waResp && (waResp.key || waResp.message || waResp.status === 'PENDING' || statusCode === null)) { sent.push('whatsapp'); }
  else { failed.push('whatsapp'); waError = 'unknown'; }
}

// --- MENSAJE DE SALIDA PARA EL AGENTE ---
const prettyNumber = built.phone_clean ? `+${built.phone_clean}` : 'tu WhatsApp';
let tool_output_text;

if (sent.length > 0 && failed.length === 0) {
  const canal = sent.length === 2 ? 'correo y WhatsApp' : sent[0] === 'email' ? 'correo' : 'WhatsApp';
  tool_output_text = `Listo ${primerNombre}, envio exitoso por ${canal} 📨 Revisalo con calma y cualquier duda me la cuentas por aca.`;
} else if (sent.length > 0 && failed.includes('whatsapp') && waError === 'numero_no_registrado') {
  tool_output_text = `Te llegó el resumen al correo ${primerNombre}. El envío por WhatsApp falló porque el número ${prettyNumber} no está registrado en WhatsApp — ¿me confirmas el número correcto y lo reintento?`;
} else if (sent.length > 0 && failed.includes('whatsapp')) {
  tool_output_text = `Te llegó el resumen por correo ${primerNombre}, pero el envío por WhatsApp falló por un tema técnico. ¿Quieres que reintente solo el WhatsApp?`;
} else if (sent.length > 0 && failed.includes('email')) {
  tool_output_text = `Te llegó el resumen por WhatsApp ${primerNombre}, pero el envío por correo falló por un tema técnico. ¿Quieres que reintente solo el correo o prefieres darme otra dirección?`;
} else if (failed.includes('whatsapp') && waError === 'numero_no_registrado') {
  tool_output_text = `El número ${prettyNumber} no está registrado en WhatsApp ${primerNombre}. ¿Me confirmas el número correcto? Lo reintento en cuanto me digas.`;
} else if (failed.length > 0) {
  tool_output_text = `No logré enviar el resumen ${primerNombre} — falló el envío por ${failed.map(c => c === 'email' ? 'correo' : 'WhatsApp').join(' y ')}. Reintenta o pasa el caso al equipo de ventas.`;
} else {
  tool_output_text = `No pude preparar el envío ${primerNombre}. Confirmame tu correo y WhatsApp y lo intento de nuevo.`;
}

return [{ json: {
  ok: sent.length > 0 && failed.length === 0,
  partial: sent.length > 0 && failed.length > 0,
  canales_enviados: sent,
  canales_fallidos: failed,
  email_error: emailError,
  wa_error: waError,
  tool_output_text,
} }];

const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
$input.item.json.pdfBase64 = buf.toString('base64');
return $input.item;

// Arma el caption del WhatsApp.
// Si el lead no pidio WhatsApp, cortocircuito: la rama entera se salta.
const built = $('Build PDF Data').first().json;
if (!built.can_whatsapp) return [];
const primerNombre = built.primerNombre || 'Cliente';

const whatsappCaption = ''
  + `Hola ${primerNombre},\n\n`
  + `Te adjunto el PDF con el resumen personalizado de lo que conversamos: las parcelas recomendadas con precios al contado y a crédito directo, el detalle según tu caso y los enlaces útiles del proyecto.\n\n`
  + `Si tienes más dudas no dudes en preguntarme por acá y con gusto te ayudo. Si ya estás decidido y quieres pasar al proceso de reserva y/o compra, dímelo y te comunico con nuestro equipo de ventas para coordinar una llamada.\n\n`
  + `*Equipo Terra Segura*\n`
  + `_Mirador de Villarrica · Región de La Araucanía_`;

// Preserva el pdfBase64 que vino del nodo anterior (PDF to Base64) para la llamada a Evolution.
return [{ json: { ...$json, whatsappCaption, phone_clean: built.phone_clean, can_whatsapp: built.can_whatsapp } }];
